#!/usr/bin/env python3
from pathlib import Path
import argparse, json, html, re, shutil, datetime

def esc(x): return html.escape(str(x), quote=True)
CSS = """
:root{--navy:#07172d;--navy2:#0e2748;--ink:#0d1b2f;--muted:#53627a;--paper:#fbf7ef;--card:#ffffff;--gold:#c99a2e;--gold2:#f1cc74;--cyan:#26c6da;--line:#e3dccf;--green:#1f9d68;--red:#bf4342;--shadow:0 26px 90px rgba(7,23,45,.14);--radius:24px;--max:1180px}*{box-sizing:border-box}html{scroll-behavior:smooth}body{margin:0;font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:linear-gradient(180deg,#fbf7ef 0%,#f4eee3 100%);color:var(--ink);line-height:1.58}a{color:#0b5e8e;text-decoration:none}a:hover{text-decoration:underline}.topbar{position:sticky;top:0;z-index:20;background:rgba(7,23,45,.97);color:#fff;border-bottom:1px solid rgba(255,255,255,.08);backdrop-filter:blur(12px)}.topbar-inner{max-width:var(--max);margin:auto;display:flex;align-items:center;justify-content:space-between;padding:14px 24px}.brand{font-weight:900;letter-spacing:.02em}.nav{display:flex;gap:16px;flex-wrap:wrap}.nav a{color:#eaf2ff;font-weight:800;font-size:.9rem}.shell{max-width:var(--max);margin:auto;padding:40px 24px 80px}.hero{background:radial-gradient(circle at 20% 20%,rgba(38,198,218,.26),transparent 28%),linear-gradient(135deg,#06152a 0%,#0d294b 58%,#111a2c 100%);color:#fff;border-radius:34px;padding:44px;box-shadow:var(--shadow);position:relative;overflow:hidden}.hero:after{content:'';position:absolute;right:-90px;top:-90px;width:300px;height:300px;border:1px solid rgba(241,204,116,.28);border-radius:50%;box-shadow:0 0 0 52px rgba(241,204,116,.04)}.kicker{font-size:.78rem;text-transform:uppercase;letter-spacing:.18em;color:var(--gold2);font-weight:900}.hero h1{font-size:clamp(2.2rem,5vw,5.2rem);line-height:.96;margin:14px 0;letter-spacing:-.07em}.hero p{max-width:850px;font-size:1.12rem;color:#dfeaff}.chips{display:flex;flex-wrap:wrap;gap:10px;margin-top:24px}.chip{border:1px solid rgba(255,255,255,.18);background:rgba(255,255,255,.08);border-radius:999px;padding:9px 13px;color:#f6fbff;font-weight:800}.panel{background:var(--card);border:1px solid var(--line);border-radius:var(--radius);padding:28px;margin-top:28px;box-shadow:0 10px 35px rgba(7,23,45,.07)}.panel.dark{background:linear-gradient(135deg,#081832,#0c2b4f);color:#fff;border-color:#1a426c}.panel.dark p,.panel.dark td{color:#e7f3ff}h2{font-size:2rem;line-height:1.05;margin:0 0 16px;letter-spacing:-.035em}h3{font-size:1.28rem;margin:24px 0 12px}.lead{font-size:1.08rem;color:#33445e}.grid{display:grid;gap:18px}.grid.two{grid-template-columns:repeat(2,minmax(0,1fr))}.grid.three{grid-template-columns:repeat(3,minmax(0,1fr))}.grid.four{grid-template-columns:repeat(4,minmax(0,1fr))}.card{border:1px solid var(--line);border-radius:20px;padding:20px;background:#fff}.metric{background:linear-gradient(180deg,#fff,#fbf7ed);border:1px solid #eadfcd;border-radius:20px;padding:18px}.metric strong{display:block;font-size:1.6rem;color:#0a2747}.caption{color:var(--muted);font-size:.92rem}.toc{display:flex;flex-wrap:wrap;gap:8px;margin:18px 0}.toc a{background:#fff;border:1px solid var(--line);border-radius:999px;padding:8px 12px;font-weight:800;color:#163152}.flow{width:100%;overflow-x:auto;padding:18px 0}.flow svg{min-width:850px;max-width:100%;height:auto}.stage-box{fill:url(#grad);stroke:#144d76;stroke-width:1}.stage-text{font-weight:900;fill:#fff;font-size:18px}.arrow{stroke:#d6a846;stroke-width:5;stroke-linecap:round}.bars{display:grid;gap:14px;margin-top:16px}.bar-row{display:grid;grid-template-columns:210px 1fr 44px;gap:14px;align-items:center}.bar-label{font-weight:900;color:#12233c}.bar-track{background:#ede4d5;border-radius:999px;overflow:hidden;height:16px}.bar-fill{height:16px;background:linear-gradient(90deg,#0b315b,#21b8c9,#f1cc74);border-radius:999px}.bar-score{font-weight:900;color:#0b315b}table{width:100%;border-collapse:separate;border-spacing:0;margin:12px 0 2px;border:1px solid var(--line);border-radius:16px;overflow:hidden;background:#fff}th{background:#0a1b33;color:#fff;text-align:left;font-size:.82rem;text-transform:uppercase;letter-spacing:.08em}th,td{padding:12px 14px;vertical-align:top;border-bottom:1px solid var(--line)}tr:last-child td{border-bottom:0}td:first-child{font-weight:800;color:#0d2544}.callout{border-left:5px solid var(--gold);background:#fff8e6;border-radius:16px;padding:18px;margin:18px 0}.claim{border:1px dashed #c59b3d;background:#fffdf6}.footer{margin-top:40px;padding-top:28px;border-top:1px solid var(--line);display:flex;justify-content:space-between;gap:20px;flex-wrap:wrap}.proof-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(230px,1fr));gap:16px}.proof-link{display:block;background:#fff;border:1px solid var(--line);border-radius:20px;padding:18px;color:#0d1b2f;box-shadow:0 10px 30px rgba(7,23,45,.06)}.proof-link:hover{transform:translateY(-2px);box-shadow:0 16px 40px rgba(7,23,45,.12);text-decoration:none}.proof-link b{display:block;font-size:1.05rem}.tag{display:inline-block;background:#eef7f8;color:#0a5570;border:1px solid #cbe8ee;border-radius:999px;padding:4px 9px;font-size:.76rem;font-weight:900;margin-bottom:10px}.mini{font-size:.86rem;color:var(--muted)}.figure-panel{background:linear-gradient(180deg,#fff,#f8f2e7);border:1px solid var(--line);border-radius:24px;padding:20px;box-shadow:0 10px 35px rgba(7,23,45,.05)}.ladder{display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:14px}.ladder .step{background:#fff;border:1px solid var(--line);border-radius:18px;padding:16px;position:relative}.step .num{width:28px;height:28px;border-radius:50%;background:#0a1b33;color:#fff;display:inline-flex;align-items:center;justify-content:center;font-weight:900;margin-bottom:10px}.faq details{border:1px solid var(--line);background:#fff;border-radius:16px;padding:14px;margin:10px 0}.faq summary{font-weight:900;cursor:pointer}.skip{position:absolute;left:-999px}.skip:focus{left:16px;top:16px;background:#fff;color:#000;padding:10px;z-index:99}@media(max-width:820px){.grid.two,.grid.three,.grid.four{grid-template-columns:1fr}.hero{padding:30px 22px}.hero h1{font-size:2.4rem}.topbar-inner{align-items:flex-start;flex-direction:column}.bar-row{grid-template-columns:1fr}.shell{padding:24px 16px 60px}table{font-size:.9rem;display:block;overflow-x:auto}.nav{gap:10px}.flow svg{min-width:720px}}"""
def nav(): return """<div class='topbar'><div class='topbar-inner'><div class='brand'>GoalOS AGIALPHA Ascension</div><nav class='nav'><a href='index.html'>Home</a><a href='proof-cards.html'>Proof Cards</a><a href='agialpha-ledger-route.html'>AGIALPHA Route</a><a href='sovereign-rsi-control-plane.html'>Sovereign RSI</a><a href='evidence-docket.html'>Evidence Docket</a></nav></div></div>"""
def html_page(title, body, desc='GoalOS AGIALPHA proof-card atlas'):
    return f"<!doctype html><html lang='en'><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>{esc(title)}</title><meta name='description' content='{esc(desc)}'><style>{CSS}</style></head><body>{nav()}<main>{body}</main></body></html>"
def svg_flow(steps):
    w=max(1100, len(steps)*145+100); x=30; parts=[]
    for i,st in enumerate(steps):
        parts.append(f"<rect x='{x}' y='40' width='125' height='72' rx='18' class='stage-box'/><text x='{x+62.5}' y='84' text-anchor='middle' class='stage-text'>{esc(st)}</text>")
        if i < len(steps)-1: parts.append(f"<line x1='{x+132}' y1='76' x2='{x+158}' y2='76' class='arrow'/>")
        x += 145
    return f"<div class='flow'><svg viewBox='0 0 {w} 155'><defs><linearGradient id='grad' x1='0' x2='1'><stop offset='0%' stop-color='#0b315b'/><stop offset='100%' stop-color='#22b8c7'/></linearGradient></defs>{''.join(parts)}</svg></div>"
def table(rows, headers):
    return '<table><thead><tr>'+''.join(f'<th>{esc(h)}</th>' for h in headers)+'</tr></thead><tbody>'+''.join('<tr>'+''.join(f'<td>{cell}</td>' for cell in row)+'</tr>' for row in rows)+'</tbody></table>'
def explain(item, kind, card):
    if kind=='skill': return f"Applies {item.lower()} to the {card.get('domain','proof')} mission so the artifact is useful, bounded, inspectable, and safe to route into review."
    if kind=='plan': return f"Defines how {item.lower()} is executed, reviewed, documented, and either promoted or rejected by the Selection Gate."
    return f"Measures whether the mission genuinely advances {card.get('domain','proof')} without creating unbounded claims or unsafe future context."
common_contracts = [('AEPGoalOSCommitRegistry', 'Records the bounded aim, scope, authority, success criteria, and claim boundary.'), ('AEPRunCommitmentRegistry', 'Records the planned run: agents, artifacts, tools, policies, evaluators, and rollback obligations.'), ('AEPAgentRegistry', 'Identifies approved specialist agents and their role scope.'), ('AEPArtifactRegistry', 'Anchors candidate artifacts, versions, hashes, and reuse status.'), ('JobRegistry', 'Creates the proof mission and its reward/bounty terms.'), ('JobClaimBondManager', 'Requires builders to commit with a bond before claiming work.'), ('ProofSubmissionRegistry', 'Receives proof submission hashes, artifact URIs, and proof metadata.'), ('ReviewerBondRegistry', 'Requires reviewers to bond, review, and wait through a challenge window.'), ('ProofCardRegistry', 'Registers public-safe proof cards after evidence passes review.'), ('ProofCredentialRegistry', 'Issues non-transferable credentials for approved proof work.'), ('ReputationRegistry', 'Updates reputation based on approved proof, review quality, and challenge outcomes.'), ('AEPEvidenceDocketRegistry', 'Anchors the Evidence Docket that makes claims inspectable.'), ('AEPSelectionGate', 'Decides whether a proven artifact receives scoped upgrade rights.'), ('AEPRolloutRouter', 'Controls canary rollout and propagation route.'), ('AEPRollbackRegistry', 'Records rollback obligations, triggers, and recovery paths.'), ('AEPChronicleRegistry', 'Preserves institutional memory for future routing and RSI.'), ('AlphaWorkUnitLedger', 'Tracks work-unit metrology, cost, validation depth, and useful effort.'), ('AEPRewardVault', 'Settles approved rewards and manages proof-work funds.'), ('TreasuryRouter', 'Routes verified value into stronger missions, audits, tools, and capability budgets.'), ('CommercializationPerformanceVault', 'Connects verified commercial milestones to governed allocation rules.'), ('AEPClaimBoundaryRegistry', 'Keeps public claims bounded and prevents overstatement.'), ('AEPConformanceRegistry', 'Checks whether artifacts and releases conform to the protocol standard.'), ('AEPFalsificationRegistry', 'Records failed claims, failed proofs, reward-hack attempts, and red-team outcomes.')]
def card_html(card, prev=None, nxt=None):
    skills=[(esc(s),esc(explain(s,'skill',card))) for s in card.get('skills',[])]
    plans=[(esc(s),esc(explain(s,'plan',card))) for s in card.get('plans',[])]
    goals=[(esc(s),esc(explain(s,'goal',card))) for s in card.get('goals',[])]
    roles=[(esc(r[0]),esc(r[1]),esc(r[2])) for r in card.get('roles',[])]
    contracts=common_contracts[:]
    cid=int(card['id'])
    if cid>=9: contracts += [('CyberBenchmarkRegistry','Defines authorized defensive benchmark tasks and scoring rules.'),('RedTeamChallengeRegistry','Records red-team challenges and falsification outcomes.'),('SecurityRegressionHarnessRegistry','Anchors regression harnesses that test whether remediation improves security without breaking operations.')]
    if cid>=10: contracts += [('IndependentReproductionRegistry','Records reproduction attempts, variance notes, and independent replay receipts.'),('CyberBenchmarkDocketRegistry','Packages benchmark tasks into public-safe dockets for review and replay.')]
    if cid>=11: contracts += [('AEPEvidenceGraphRegistry','Connects missions, artifacts, reviewers, outcomes, costs, risks, and delayed results.'),('AEPTrustEdgeRegistry','Stores evidence-backed trust links between artifacts, reviewers, domains, and outcomes.'),('AEPRouteMemoryRegistry','Stores which proven artifacts should influence future routing decisions.'),('AEPDelayedOutcomeRegistry','Records whether selected artifacts continued to perform after deployment or review delay.')]
    contract_rows=[(str(i+1),esc(a),esc(b)) for i,(a,b) in enumerate(contracts)]
    ev=['GoalOSCommit','RunCommitment','ProofBundle','Evaluator report','Reviewer attestation','Red-team / falsification report','Cost and risk ledger','SelectionCertificate or rejection note','Rollback path','ChronicleEntry','Delayed outcome update']
    ev_rows=[(str(i+1),esc(e),'Required before any public claim is promoted or any artifact earns scoped upgrade rights.') for i,e in enumerate(ev)]
    links=(f"<a href='proof-card-{prev}.html'>Previous</a>" if prev else '') + " &nbsp; <a href='proof-cards.html'>Back to atlas</a> &nbsp; " + (f"<a href='proof-card-{nxt}.html'>Next</a>" if nxt else '')
    labels=['Proof clarity','Evidence depth','Replayability','RSI readiness','Enterprise value','Execution moat']
    score_base=84+cid%5
    bars='<div class="bars">'+''.join(f"<div class='bar-row'><div class='bar-label'>{l}</div><div class='bar-track'><div class='bar-fill' style='width:{min(98,score_base+i*2)}%'></div></div><div class='bar-score'>{min(98,score_base+i*2)}</div></div>" for i,l in enumerate(labels))+'</div>'
    body=f"""<section class='shell'><section class='hero'><div class='kicker'>Proof Card {esc(card['id'])} · {esc(card.get('domain','Proof'))}</div><h1>{esc(card['title'])}</h1><p>{esc(card['thesis'])}</p><div class='chips'><span class='chip'>AGIALPHA-coordinated</span><span class='chip'>Evidence Docket</span><span class='chip'>RSI upgrade rights</span><span class='chip'>{esc(card.get('status','Experimental'))}</span></div></section><nav class='toc'><a href='#summary'>Summary</a><a href='#flow'>Visual flow</a><a href='#agents'>Agents</a><a href='#skills'>Skills / plans / goals</a><a href='#contracts'>Contracts</a><a href='#evidence'>Evidence</a><a href='#rsi'>RSI</a><a href='#boundary'>Boundary</a></nav><section class='panel' id='summary'><h2>In plain English</h2><p class='lead'>{esc(card['plain'])}</p><div class='callout'><strong>Proof mission:</strong> {esc(card['mission'])}</div></section><section class='panel'><h2>Why this matters</h2><p>{esc(card['why'])}</p><div class='grid four'><div class='metric'><strong>Proof</strong><span>Claims become inspectable.</span></div><div class='metric'><strong>Trust</strong><span>Reviewers and red teams validate evidence.</span></div><div class='metric'><strong>RSI</strong><span>Only proven artifacts shape future work.</span></div><div class='metric'><strong>Value</strong><span>Verified capability can be reused and reinvested.</span></div></div></section><section class='panel' id='flow'><h2>Visual operating flow</h2><div class='figure-panel'>{svg_flow(card.get('flow',['Aim','Build','Prove','Review','Select']))}</div><h3>Proof maturity dashboard</h3>{bars}</section><section class='panel'><h2>Value-to-capability ladder</h2><div class='ladder'><div class='step'><span class='num'>1</span><h3>Mission</h3><p>Bound the goal, scope, authority, success criteria, and claim boundary.</p></div><div class='step'><span class='num'>2</span><h3>Artifact</h3><p>Create a candidate workflow, remediation, benchmark, control, or operating surface.</p></div><div class='step'><span class='num'>3</span><h3>Evidence</h3><p>Package proof, evaluation, cost, risk, reproduction, and reviewer evidence.</p></div><div class='step'><span class='num'>4</span><h3>Selection</h3><p>Grant scoped upgrade rights only after review and challenge logic.</p></div><div class='step'><span class='num'>5</span><h3>Capability</h3><p>Route future work through what proved itself and remember the result.</p></div></div></section><section class='panel' id='agents'><h2>Large specialist-agent operating theater</h2><p>GoalOS-native α‑AGI Ascension coordinates specialist cells with bounded mandates and inspectable outputs.</p>{table(roles,['Agent cell','Responsibility','Output'])}</section><section class='panel' id='skills'><h2>Skills, plans, and goals</h2><div class='grid two'><div><h3>Skills used</h3>{table(skills,['Skill','Explanation'])}</div><div><h3>Plans used</h3>{table(plans,['Plan','Explanation'])}</div></div><h3>Goals used</h3>{table(goals,['Goal','Explanation'])}</section><section class='panel' id='contracts'><h2>AGIALPHA + smart-contract route</h2><p>AGIALPHA coordinates proof-settled mission budgets, bonds, proof submission, review, proof-card actions, credential issuance, reputation-linked routing, reward-vault settlement, treasury reinvestment, and Chronicle memory.</p>{table(contract_rows,['#','Contract / registry','Purpose'])}</section><section class='panel' id='evidence'><h2>Evidence Docket checklist</h2><p>Private data stays off-chain; proof commitments and summaries remain inspectable.</p>{table(ev_rows,['#','Evidence item','Purpose'])}</section><section class='panel' id='rsi'><h2>Recursive Self-Improvement logic</h2><p>RSI is proof-backed upgrade rights. Unproven work cannot become future operating context. Replayed, reviewed, selected work can.</p><div class='figure-panel'>{svg_flow(['Weakness','Candidate','Proof','Review','Selection','Upgrade','Future Work'])}</div></section><section class='panel claim' id='boundary'><h2>Claim boundary</h2><p>Experimental proof-card page. It does not claim achieved AGI, achieved superintelligence, guaranteed financial return, legal/tax/security approval, Ethereum mainnet deployment, or Kardashev Type II achievement.</p></section><section class='panel faq'><h2>FAQ</h2><details open><summary>What makes this substantial?</summary><p>It links a mission to specialist agents, evidence, contracts, AGIALPHA coordination, RSI upgrade rights, and claim boundaries.</p></details><details><summary>What is the execution moat?</summary><p>The evidence graph: repeated missions, ProofBundles, reviewer attestations, red-team outcomes, settlement receipts, delayed outcomes, and routing memory.</p></details></section><div class='footer'><div>{links}</div><strong>GoalOS AGIALPHA Ascension · proof-card atlas</strong></div></section>"""
    return html_page(f"Proof Card {card['id']} — {card['title']}", body, card['plain'])
def index_html(cards):
    links=''.join(f"<a class='proof-link' href='proof-card-{c['id']}.html'><span class='tag'>Proof Card {c['id']}</span><b>{esc(c['title'])}</b><p>{esc(c['thesis'])}</p></a>" for c in cards)
    return html_page('GoalOS AGIALPHA Ascension — Institutional Proof Atlas',f"<section class='shell'><section class='hero'><div class='kicker'>GoalOS AGIALPHA Ascension</div><h1>Institutional Proof Atlas</h1><p>Proof Cards 001–011 explain how GoalOS turns AI work into auditable institutional capability: AGIALPHA coordinates proof-settled missions, Evidence Dockets make claims inspectable, and RSI reuses only what proved itself.</p><div class='chips'><span class='chip'>11 stable proof-card pages</span><span class='chip'>AGIALPHA contract routes</span><span class='chip'>Evidence Dockets</span><span class='chip'>RSI upgrade rights</span></div></section><section class='panel'><h2>Proof Card Command Center</h2><p class='lead'>Each card is a substantial public-safe micro-dossier with plain-English summaries, multi-agent operating theaters, skills/plans/goals, contract routes, Evidence Docket checklists, charts, and claim boundaries.</p><div class='proof-grid'>{links}</div></section><section class='panel dark'><h2>The execution moat</h2><p>A webpage can be copied. A long-running evidence graph cannot be retroactively fabricated.</p></section></section>")
def gallery_html(cards):
    links=''.join(f"<a class='proof-link' href='proof-card-{c['id']}.html'><span class='tag'>Proof Card {c['id']}</span><b>{esc(c['title'])}</b><p>{esc(c['plain'][:220])}...</p></a>" for c in cards)
    return html_page('Proof Cards — GoalOS AGIALPHA Ascension',f"<section class='shell'><section class='hero'><div class='kicker'>Proof Cards</div><h1>Institutional proof-card atlas</h1><p>Stable, substantial pages for Proof Cards 001–011.</p></section><section class='panel'><div class='proof-grid'>{links}</div></section></section>")
def support_html(title,text):
    return html_page(title,f"<section class='shell'><section class='hero'><div class='kicker'>GoalOS AGIALPHA Ascension</div><h1>{esc(title)}</h1><p>{esc(text)}</p></section><section class='panel'><h2>Operating route</h2>{svg_flow(['Aim','Route','Build','Prove','Review','Select','Chronicle'])}<p class='lead'>{esc(text)}</p></section></section>")
def integrate(site, data_path):
    site=Path(site); site.mkdir(parents=True,exist_ok=True)
    cards=json.loads(Path(data_path).read_text(encoding='utf-8'))['cards']
    # preserve previous site by leaving assets/files. Replace index to make proof cards visible at root.
    (site/'index.html').write_text(index_html(cards),encoding='utf-8')
    (site/'proof-cards.html').write_text(gallery_html(cards),encoding='utf-8')
    for i,c in enumerate(cards):
        prev=cards[i-1]['id'] if i else None
        nxt=cards[i+1]['id'] if i < len(cards)-1 else None
        (site/f"proof-card-{c['id']}.html").write_text(card_html(c,prev,nxt),encoding='utf-8')
    support={
        'agialpha-ledger-route.html':('AGIALPHA Ledger Route','AGIALPHA coordinates mission budgets, bonds, proof submission, review, proof-card actions, credentials, reputation, reward-vault settlement, treasury routing, and Chronicle memory.'),
        'sovereign-rsi-control-plane.html':('Sovereign RSI Control Plane','RSI is proof-backed upgrade rights: artifacts influence future work only after evidence, evaluation, review, challenge, selection, rollback readiness, and Chronicle memory.'),
        'evidence-docket.html':('Evidence Docket','Evidence Dockets make claims inspectable through GoalOSCommit, RunCommitment, ProofBundle, evaluator report, reviewer attestation, cost/risk ledger, rollback path, and Chronicle entry.'),
        'season-001.html':('Season 001','Season 001 turns the proof-card atlas into a mission portfolio: proof work, review work, evidence work, and public-safe capability production.'),
        'share.html':('Share Kit','Share the public-safe story: GoalOS turns AI work into auditable institutional capability; AGIALPHA coordinates proof-settled missions; RSI reuses only what proved itself.'),
    }
    for fn,(t,txt) in support.items(): (site/fn).write_text(support_html(t,txt),encoding='utf-8')
    (site/'.nojekyll').write_text('',encoding='utf-8')
    print(f'Integrated {len(cards)} premium proof cards into {site}.')
def main():
    ap=argparse.ArgumentParser()
    ap.add_argument('--site', default='site')
    ap.add_argument('--data', default='data/proof-cards/proof-cards-v23.json')
    args=ap.parse_args()
    integrate(args.site,args.data)
if __name__=='__main__': main()
